-- 版本 1.4.0：同步默认库字典与菜单、按钮资源。
-- 前置条件：已按 README 顺序执行同版本前两个默认库脚本，并已备份 thinglinks_ds_c_defaults。
-- 更新范围：指定字典、资源和已知废弃资源关系；不修改范围外的自定义数据。
-- 字典和资源通过临时表 UPSERT，脚本可安全重复执行。
-- 目标唯一键如被其他主键占用，失败门禁会中止迁移，不覆盖自定义记录。

SET NAMES utf8mb4;

DROP TEMPORARY TABLE IF EXISTS `_tl_140_dict_stage`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_resource_stage`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_retired_dict`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_retired_resource`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_conflict_gate`;

CREATE TEMPORARY TABLE `_tl_140_dict_stage` LIKE `def_dict`;
CREATE TEMPORARY TABLE `_tl_140_resource_stage` LIKE `def_resource`;
CREATE TEMPORARY TABLE `_tl_140_retired_dict` (
  `id` BIGINT NOT NULL,
  `parent_id` BIGINT NOT NULL,
  `parent_key` VARCHAR(255) NULL,
  `key_` VARCHAR(255) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE = InnoDB;
CREATE TEMPORARY TABLE `_tl_140_retired_resource` (
  `id` BIGINT NOT NULL,
  `application_id` BIGINT NOT NULL,
  `code` VARCHAR(255) NOT NULL,
  `parent_id` BIGINT NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE = InnoDB;
CREATE TEMPORARY TABLE `_tl_140_conflict_gate` (
  `id` TINYINT NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE = InnoDB;


START TRANSACTION;

-- 仅删除历史基线中身份仍然完全匹配的废弃字典；同 ID 的自定义记录保持不变。

DELETE `current`
FROM `def_dict` AS `current`
INNER JOIN `_tl_140_retired_dict` AS `retired`
  ON `current`.`id` = `retired`.`id`
 AND `current`.`parent_id` = `retired`.`parent_id`
 AND `current`.`parent_key` <=> `retired`.`parent_key`
 AND `current`.`key_` = `retired`.`key_`;


-- 主键与业务唯一键必须指向同一条受管字典记录。
SELECT 1
FROM `def_dict` AS `current`
INNER JOIN `_tl_140_dict_stage` AS `incoming` ON `current`.`id` = `incoming`.`id`
WHERE NOT (`current`.`parent_id` <=> `incoming`.`parent_id`)
   OR `current`.`key_` <> `incoming`.`key_`
LIMIT 1;

SELECT 1
FROM `def_dict` AS `current`
INNER JOIN `_tl_140_dict_stage` AS `incoming` ON `current`.`parent_id` = `incoming`.`parent_id` AND `current`.`key_` = `incoming`.`key_`
WHERE `current`.`id` <> `incoming`.`id`
LIMIT 1;

SELECT `incoming`.`id`, `incoming`.`parent_id`, `incoming`.`parent_key`, `incoming`.`dict_group`, `incoming`.`classify`, `incoming`.`data_type`, `incoming`.`key_`, `incoming`.`name`, `incoming`.`state`, `incoming`.`remark`, `incoming`.`sort_value`, `incoming`.`icon`, `incoming`.`css_style`, `incoming`.`css_class`, `incoming`.`prop_type`, `incoming`.`i18n_json`, `incoming`.`created_by`, `incoming`.`created_time`, `incoming`.`updated_by`, `incoming`.`updated_time`
FROM `_tl_140_dict_stage` AS `incoming`
WHERE TRUE
ON DUPLICATE KEY UPDATE
  `parent_id` = VALUES(`parent_id`),
  `parent_key` = VALUES(`parent_key`),
  `dict_group` = VALUES(`dict_group`),
  `classify` = VALUES(`classify`),
  `data_type` = VALUES(`data_type`),
  `key_` = VALUES(`key_`),
  `name` = VALUES(`name`),
  `state` = VALUES(`state`),
  `remark` = VALUES(`remark`),
  `sort_value` = VALUES(`sort_value`),
  `icon` = VALUES(`icon`),
  `css_style` = VALUES(`css_style`),
  `css_class` = VALUES(`css_class`),
  `prop_type` = VALUES(`prop_type`),
  `i18n_json` = VALUES(`i18n_json`),
  `created_by` = VALUES(`created_by`),
  `created_time` = VALUES(`created_time`),
  `updated_by` = VALUES(`updated_by`),
  `updated_time` = VALUES(`updated_time`);

