UPDATE `def_dict` SET `parent_id` = 0, `parent_key` = NULL, `dict_group` = NULL, `classify` = '10', `data_type` = '1', `key_` = 'RULE_ALARM_CHANNEL_TYPE', `name` = '告警规则渠道类型', `state` = b'1', `remark` = '告警规则渠道类型（默认0）0:钉钉|1:企业微信|2:飞书|3:站内信', `sort_value` = 1, `icon` = '', `css_style` = '', `css_class` = '', `prop_type` = '', `i18n_json` = '{\"zh-CN\": \"告警规则渠道类型\", \"en-US\": \"Alarm Rule Channel Type\", \"ja\": \"アラームルールチャネルタイプ\"}', `created_by` = 1452186486253289472, `created_time` = '2023-09-12 12:33:44', `updated_by` = 1452186486253289472, `updated_time` = '2023-09-12 12:33:44' WHERE `id` = 405377314252128272 AND `key_` = 'RULE_ALARM_CHANNEL_TYPE';

