-- 已知废弃资源清单：只收录能由上一版基线确认身份的 37 条旧资源。

-- 关系数据无法安全映射到新资源，仅在资源身份完整匹配时清理旧关系。
DELETE `api`
FROM `def_resource_api` AS `api`
INNER JOIN `def_resource` AS `resource` ON `resource`.`id` = `api`.`resource_id`
INNER JOIN `_tl_140_retired_resource` AS `retired`
  ON `retired`.`id` = `resource`.`id`
 AND `retired`.`application_id` = `resource`.`application_id`
 AND `retired`.`code` = `resource`.`code`
 AND `retired`.`parent_id` = `resource`.`parent_id`;

DELETE `rel`
FROM `def_tenant_resource_rel` AS `rel`
INNER JOIN `def_resource` AS `resource` ON `resource`.`id` = `rel`.`resource_id`
INNER JOIN `_tl_140_retired_resource` AS `retired`
  ON `retired`.`id` = `resource`.`id`
 AND `retired`.`application_id` = `resource`.`application_id`
 AND `retired`.`code` = `resource`.`code`
 AND `retired`.`parent_id` = `resource`.`parent_id`;

UPDATE `def_gen_table` AS `gen`
INNER JOIN `def_resource` AS `resource` ON `resource`.`id` = `gen`.`menu_parent_id`
INNER JOIN `_tl_140_retired_resource` AS `retired`
  ON `retired`.`id` = `resource`.`id`
 AND `retired`.`application_id` = `resource`.`application_id`
 AND `retired`.`code` = `resource`.`code`
 AND `retired`.`parent_id` = `resource`.`parent_id`
SET `gen`.`menu_parent_id` = NULL;

DELETE `resource`
FROM `def_resource` AS `resource`
INNER JOIN `_tl_140_retired_resource` AS `retired`
  ON `retired`.`id` = `resource`.`id`
 AND `retired`.`application_id` = `resource`.`application_id`
 AND `retired`.`code` = `resource`.`code`
 AND `retired`.`parent_id` = `resource`.`parent_id`;


-- 主键与业务唯一键必须指向同一条受管资源记录。
SELECT 1
FROM `def_resource` AS `current`
INNER JOIN `_tl_140_resource_stage` AS `incoming` ON `current`.`id` = `incoming`.`id`
WHERE `current`.`code` <> `incoming`.`code`
LIMIT 1;

SELECT 1
FROM `def_resource` AS `current`
INNER JOIN `_tl_140_resource_stage` AS `incoming` ON `current`.`code` = `incoming`.`code`
WHERE `current`.`id` <> `incoming`.`id`
LIMIT 1;

SELECT `incoming`.`id`, `incoming`.`application_id`, `incoming`.`code`, `incoming`.`name`, `incoming`.`resource_type`, `incoming`.`parent_id`, `incoming`.`open_with`, `incoming`.`describe_`, `incoming`.`path`, `incoming`.`component`, `incoming`.`link`, `incoming`.`redirect`, `incoming`.`icon`, `incoming`.`is_hidden`, `incoming`.`is_general`, `incoming`.`state`, `incoming`.`sort_value`, `incoming`.`sub_group`, `incoming`.`field_is_secret`, `incoming`.`field_is_edit`, `incoming`.`data_scope`, `incoming`.`custom_class`, `incoming`.`is_def`, `incoming`.`tree_path`, `incoming`.`tree_grade`, `incoming`.`meta_json`, `incoming`.`created_by`, `incoming`.`created_time`, `incoming`.`updated_by`, `incoming`.`updated_time`
FROM `_tl_140_resource_stage` AS `incoming`
WHERE TRUE
ON DUPLICATE KEY UPDATE
  `application_id` = VALUES(`application_id`),
  `code` = VALUES(`code`),
  `name` = VALUES(`name`),
  `resource_type` = VALUES(`resource_type`),
  `parent_id` = VALUES(`parent_id`),
  `open_with` = VALUES(`open_with`),
  `describe_` = VALUES(`describe_`),
  `path` = VALUES(`path`),
  `component` = VALUES(`component`),
  `link` = VALUES(`link`),
  `redirect` = VALUES(`redirect`),
  `icon` = VALUES(`icon`),
  `is_hidden` = VALUES(`is_hidden`),
  `is_general` = VALUES(`is_general`),
  `state` = VALUES(`state`),
  `sort_value` = VALUES(`sort_value`),
  `sub_group` = VALUES(`sub_group`),
  `field_is_secret` = VALUES(`field_is_secret`),
  `field_is_edit` = VALUES(`field_is_edit`),
  `data_scope` = VALUES(`data_scope`),
  `custom_class` = VALUES(`custom_class`),
  `is_def` = VALUES(`is_def`),
  `tree_path` = VALUES(`tree_path`),
  `tree_grade` = VALUES(`tree_grade`),
  `meta_json` = VALUES(`meta_json`),
  `created_by` = VALUES(`created_by`),
  `created_time` = VALUES(`created_time`),
  `updated_by` = VALUES(`updated_by`),
  `updated_time` = VALUES(`updated_time`);

