-- 失败门禁：临时表中的所有主键必须已落库。
SELECT 1
FROM `_tl_140_dict_stage` AS `stage`
LEFT JOIN `def_dict` AS `target` ON `target`.`id` = `stage`.`id`
WHERE `target`.`id` IS NULL
LIMIT 1;

SELECT 1
FROM `_tl_140_resource_stage` AS `stage`
LEFT JOIN `def_resource` AS `target` ON `target`.`id` = `stage`.`id`
WHERE `target`.`id` IS NULL
LIMIT 1;

-- 失败门禁：核心根字典和公共资源不得被其他用途占用。
SELECT 1
WHERE NOT EXISTS (
  SELECT 1 FROM `def_dict`
  WHERE `id` = 371982148229398528 AND `key_` = 'LINK_DEVICE_ACTION_TYPE'
)
   OR NOT EXISTS (
  SELECT 1 FROM `def_dict`
  WHERE `id` = 405377314252128272 AND `key_` = 'RULE_ALARM_CHANNEL_TYPE'
)
   OR NOT EXISTS (
  SELECT 1 FROM `def_dict`
  WHERE `id` = 524352044412200333 AND `key_` = 'RULE_CONDITION_DEVICE_ACTION_TIRGGER_TYPE'
)
   OR NOT EXISTS (
  SELECT 1 FROM `def_resource`
  WHERE `id` = 1449732868459724800 AND `code` = 'basic:application:myApplication'
);

-- 提交前一致性门禁：任何孤儿记录都会通过重复主键错误中止迁移。
SELECT 1
FROM (
  SELECT `api`.`resource_id`
  FROM `def_resource_api` AS `api`
  LEFT JOIN `def_resource` AS `resource` ON `resource`.`id` = `api`.`resource_id`
  WHERE `resource`.`id` IS NULL

  UNION ALL

  SELECT `rel`.`resource_id`
  FROM `def_tenant_resource_rel` AS `rel`
  LEFT JOIN `def_resource` AS `resource` ON `resource`.`id` = `rel`.`resource_id`
  WHERE `resource`.`id` IS NULL

  UNION ALL

  SELECT `gen`.`menu_parent_id`
  FROM `def_gen_table` AS `gen`
  LEFT JOIN `def_resource` AS `resource` ON `resource`.`id` = `gen`.`menu_parent_id`
  WHERE `gen`.`menu_parent_id` IS NOT NULL
    AND `gen`.`menu_parent_id` <> 0
    AND `resource`.`id` IS NULL

  UNION ALL

  SELECT `dict`.`parent_id`
  FROM `def_dict` AS `dict`
  LEFT JOIN `def_dict` AS `parent` ON `parent`.`id` = `dict`.`parent_id`
  WHERE `dict`.`parent_id` <> 0
    AND `parent`.`id` IS NULL
) AS `orphan`
LIMIT 1;

SELECT 1
WHERE (SELECT COUNT(*) FROM `def_dict` WHERE `id` IN (
  1989100000000000050,
  1989100000000000051,
  1989100000000000052,
  1989100000000000053
)) <> 4
   OR (SELECT COUNT(*) FROM `def_resource` WHERE `id` IN (
  1921000000000010001,
  1921000000000020001,
  1921000000000020002,
  1921000000000020003,
  1921000000000020004,
  1989000000000000002,
  1989000000000000003,
  1989000000000000004
)) <> 8;

COMMIT;

DROP TEMPORARY TABLE IF EXISTS `_tl_140_dict_stage`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_resource_stage`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_retired_dict`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_retired_resource`;
DROP TEMPORARY TABLE IF EXISTS `_tl_140_conflict_gate`;

-- 验证：以下结果应分别为 4、8、0、0、0。
SELECT COUNT(*) AS `product_version_dict_count_should_be_4`
FROM `def_dict`
WHERE `id` IN (
  1989100000000000050,
  1989100000000000051,
  1989100000000000052,
  1989100000000000053
);

SELECT COUNT(*) AS `key_resource_count_should_be_8`
FROM `def_resource`
WHERE `id` IN (
  1921000000000010001,
  1921000000000020001,
  1921000000000020002,
  1921000000000020003,
  1921000000000020004,
  1989000000000000002,
  1989000000000000003,
  1989000000000000004
);

SELECT COUNT(*) AS `def_resource_api_orphan_count_should_be_0`
FROM `def_resource_api` AS `api`
LEFT JOIN `def_resource` AS `resource` ON `resource`.`id` = `api`.`resource_id`
WHERE `resource`.`id` IS NULL;

SELECT COUNT(*) AS `def_tenant_resource_rel_orphan_count_should_be_0`
FROM `def_tenant_resource_rel` AS `rel`
LEFT JOIN `def_resource` AS `resource` ON `resource`.`id` = `rel`.`resource_id`
WHERE `resource`.`id` IS NULL;

SELECT COUNT(*) AS `def_gen_table_menu_orphan_count_should_be_0`
FROM `def_gen_table` AS `gen`
LEFT JOIN `def_resource` AS `resource` ON `resource`.`id` = `gen`.`menu_parent_id`
WHERE `gen`.`menu_parent_id` IS NOT NULL
  AND `gen`.`menu_parent_id` <> 0
  AND `resource`.`id` IS NULL;
